<?php
 namespace WPAICG\Core\Providers\Azure\Methods; if (!defined('ABSPATH')) { exit; } function format_sse_logic_for_payload_formatter(array $messages, string $system_instruction, array $ai_params, string $model, bool $request_usage = true): array { $history_for_shared_format = array_map(function($msg) { if ($msg['role'] === 'bot') $msg['role'] = 'assistant'; return $msg; }, $messages); $payload = _shared_format_logic($system_instruction, $history_for_shared_format, $ai_params); $payload['stream'] = true; if ($request_usage) { $payload['stream_options'] = ['include_usage' => true]; } return $payload; }